import { useState, useEffect } from "react"
import "./index.css"

// --- CONSTANTS ---
const WORK_TIME = 25 * 60 // 25 minutes in seconds
const SHORT_BREAK = 5 * 60 // 5 minutes in seconds
const LONG_BREAK = 15 * 60 // 15 minutes in seconds

type SessionPhase = "work" | "short break" | "long break"

interface TimerState {
  phase: SessionPhase
  timeRemaining: number // Seconds
}

// --- COMPONENTS ---

/** Displays the current time in MM:SS format */
const Clock: React.FC<{ totalSeconds: number }> = ({ totalSeconds }) => {
  const minutes = Math.floor(totalSeconds / 60)
  const seconds = totalSeconds % 60
  return (
  <div className="text-5xl sm:text-7xl font-extrabold tracking-tighter">
    {String(minutes).padStart(2, '0')}:{String(seconds).padStart(2, '0')}
  </div>
)

/** Progress bar with color changes based on phase */
const ProgressBar: React.FC<{ totalSeconds: number; remainingSeconds: number }> = ({ totalSeconds, remainingSeconds }) => {
  const percentage = Math.max(0, (remainingSeconds / totalSeconds) * 100)
  return (
  <div className="w-full h-2 bg-bg-1 rounded-full overflow-hidden mt-2">
    <div
      className={`h-full transition-all duration-700 ease-out ${percentage > 30 ? 'bg-gradient-to-r from-accent to-opacity-50' : 'bg-danger'} ${percentage < 15 ? 'scale-[1.05]]' : ''}`}
      style={{ width: `${percentage}%` }}
    />
  </div>
)

/** Main Timer Component */
const PomodoroTimer: React.FC<{ isRunning: boolean; totalSeconds: number; }> = ({ isRunning, totalSeconds }) => {
  return (
  <div className="flex flex-col items-center justify-center py-12">
    <h2 className={`text-3xl md:text-5xl font-bold ${isRunning ? 'text-accent' : 'text-white'} transition-colors duration-500`}>
      {totalSeconds > 0 ? (totalSeconds / 60).toFixed(1) + "h" : "Time Up"}
    </h2>
    <div className="w-full max-w-md">
      <ProgressBar totalSeconds={totalSeconds} remainingSeconds={totalSeconds} />
    </div>
  </div>
)

/** Cycle Navigation */
const ButtonGroup: React.FC<{ currentPhase: SessionPhase; onNextPhase: () => void }> = ({ currentPhase, onNextPhase }) => {
  return (
  <div className="flex justify-center space-x-4 mt-8">
    <button
      onClick={onPreviousPhase}
      disabled={!isRunning && isRunning === 'work'}
      className={`px-6 py-3 rounded-xl transition-all duration-300 ${currentPhase !== 'work' ? 'bg-accent hover:shadow-lg hover:scale-[1.02] active:scale-95' : 'border border-gray-700 text-gray-400 cursor-not-allowed' : ''}`}
    >
      {currentPhase === 'work' ? "Previous" : currentPhase === 'break' ? "Start" : "Next"}
  </button>
  <button
    onClick={() => onReset()}
    disabled={!isRunning && isRunning === 'work'}
    className={`px-8 py-3 rounded-xl transition-all duration-300 ${isRunning ? 'bg-danger hover:shadow-xl active:scale-[0.98]' : 'border border-gray-700 text-gray-500 cursor-not-allowed' : ''}`}
  >
    {isRunning ? "Stop" : "Reset"}
</button>
)

/** Main App Component */
const PomodoroTimerApp: React.FC = () => {
  const [isCounting, setIsCounting] = useState(false)
  const [phase, setPhase] = useState<SessionPhase>("work") // Initial phase
  const [timeRemaining, setTimeRemaining] = useState<number>(WORK_TIME)

  // --- TIMER LOGIC ---
  useEffect(() => {
    let interval: NodeJS.Timer | null = null

    if (isCounting && timeRemaining > 0) {
      interval = setInterval(() => {
        setTimeRemaining(prevTime => prevTime - 1)
        if (timeRemaining <= 0) {
          clearInterval(interval!)
          handlePhaseEnd()
        }
      }, 1000)

      return () => clearInterval(interval!)
    } else if (!isRunning && timeRemaining === 0) {
      setIsCounting(false)
    }
  }, [isCounting, timeRemaining])

// --- PHASE HANDLERS ---

/** Handles transition when a phase ends (Work -> Short Break -> Long Break) */
const handlePhaseEnd = () => {
  if (!isRunning) return

  let nextPhase: SessionPhase | null = null
  switch (phase) {
    case "work":
      nextPhase = "short break"
      setTimeRemaining(SHORT_BREAK)
      setPhase(nextPhase!)
      setIsCounting(true)
      break
    case "short break":
      nextPhase = "long break"
      setTimeRemaining(LONG_BREAK)
      setPhase(nextPhase!)
      setIsCounting(true)
      break
    case "long break":
      // Full cycle complete
      setIsCounting(false)
      setPhase("work")
      setTimeRemaining(WORK_TIME)
      break
  }
}

/** Cycles through phases: Work -> Short Break -> Long Break -> Loop */
const handleNextPhase = () => {
  if (!isRunning && timeRemaining !== 0) return

  let nextPhase: SessionPhase | null = null
  switch (phase) {
    case "work":
      nextPhase = "short break"
      setTimeRemaining(SHORT_BREAK)
      setPhase(nextPhase!)
      setIsCounting(true)
      break
    case "short break":
      nextPhase = "long break"
      setTimeRemaining(LONG_BREAK)
      setPhase(nextPhase!)
      setIsCounting(true)
      break
    case "long break":
    default:
      // Full cycle complete, reset to work
      setIsCounting(false)
      setPhase("work")
      setTimeRemaining(WORK_TIME)
      break
  }
}

/** Resets timer to full work session */
const handleReset = () => {
  setIsCounting(false)
  setPhase("work")
  setTimeRemaining(WORK_TIME)
}

// --- MAIN RENDER ---
return (
  <div className="min-h-screen bg-bg-0 text-white font-sans">
  <header className="sticky top-0 z-50 bg-bg-1/8 backdrop-blur-md backdrop-blur-sm border-b border-gray-800 py-4 px-4 sm:px-8 shadow-xl">
    <div className="container flex justify-between items-center">
      <h1 className="text-2xl md:text-3xl font-extrabold tracking-tight">
        Pomodoro Timer
      </h1>
      <div className={`flex items-center ${isRunning ? 'text-accent' : 'text-gray-500'} text-sm`}>
        {isCounting && timeRemaining > 0 ? (
          <span className="mr-2">{Math.floor(timeRemaining / 60)}</span>
        ) : (
          <div className={`w-3 h-3 rounded-full ${isRunning ? 'bg-accent' : 'bg-gray-700'} animate-pulse'}`} />
        )}
        {isCounting && timeRemaining > 0 ? (
          <span className="ml-2">{Math.floor(timeRemaining / 60 * 10) / 10}:{"".padStart(2, '0')}{timeRemaining % 60 < 10 ? '0' : ''}</span>
        ) : ""
      </div>
    </div>
  </header>

  <main className="flex flex-col items-center justify-center py-16 md:py-24">
    {/* Main Timer Display */}
    <PomodoroTimer 
      isRunning={isCounting} 
      totalSeconds={timeRemaining} 
    />

    {/* Session Status Card */}
    <div className="w-full max-w-md bg-bg-1 p-8 rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.6)] transition-all duration-700 ${isRunning ? 'border-2 border-accent' : ''}">
      <div className="flex justify-between items-center mb-4">
        <span className={`text-lg font-semibold ${isCounting && timeRemaining > 0 ? 'text-accent' : 'text-gray-400'}`}>
          {phase.toUpperCase()}
        </span>
        <div className={`flex items-center gap-2 ${isRunning ? 'text-accent' : 'text-gray-500'}`}>
          <span className="w-3 h-3 rounded-full ${isCounting && timeRemaining > 0 ? 'bg-accent' : 'bg-gray-700'} animate-pulse" />
        </span>
      </div>

      {isRunning && timeRemaining > 0 && (
        <>
          <div className="text-xl md:text-2xl font-medium mb-6">
            <span className="text-lg md:text-xl mr-2">{Math.floor(timeRemaining / 60)}</span>
            <span className="text-gray-400">TIME LEFT</span>
          </div>
          <ProgressBar totalSeconds={timeRemaining} remainingSeconds={timeRemaining} />
        </>
      )}

      {!isRunning && timeRemaining === 0 && (
        <div className={`p-6 rounded-xl ${isCounting ? 'bg-bg-2' : 'bg-gradient-to-r from-bg-1/5 to-bg-1/3'} border ${isCounting ? 'border-accent' : ''} shadow-inner`}`}>
          <h3 className="text-2xl font-bold mb-2">
            {phase === "work" ? "Deep Focus" : phase === "short break" ? "Quick Break" : "Long Break"}
          </h3>
          <p className={`text-base ${isCounting && timeRemaining > 0 ? 'text-accent' : 'text-gray-400'} transition-colors duration-500`}>
            {phase === "work" ? (
              <span className="font-mono tracking-wider">{Math.floor(timeRemaining / 60)}</span> +{"".repeat(Math.floor(timeRemaining % 60))}
            ) : phase === "short break" ? (
              <span>{Math.floor(timeRemaining / 60)}</span>
            ) : phase === "long break" ? (
              <span>{Math.floor(timeRemaining / 60)}</span>
            ) : ""
          </p>
        </>
      )}

      {/* Controls */}
      <div className="flex justify-center items-center gap-4 mt-8">
        <button
          onClick={handleNextPhase}
          disabled={!isRunning && timeRemaining === 0}
          className={`px-8 py-3 rounded-full text-lg font-semibold transition-all duration-500 ${isRunning ? 'bg-accent hover:shadow-2xl hover:scale-[1.02]' : 'border border-gray-700 text-gray-600 cursor-not-allowed' : ''}`}
        >
          {isRunning && timeRemaining > 0 ? "Next Phase" : (
            timeRemaining === 0 ? (
              <span className="animate-bounce">READY</span>
            ) : (
              <span>{phase.toUpperCase()}</span>
            )
          )}
      </button>
      <button
        onClick={handleReset}
        disabled={!isRunning && timeRemaining !== 0}
        className={`px-8 py-3 rounded-full text-lg font-semibold transition-all duration-500 ${isRunning || timeRemaining !== 0 ? 'bg-danger hover:shadow-2xl active:scale-[0.98]' : 'border border-gray-700 text-gray-600 cursor-not-allowed' : ''}`}
      >
        {isRunning || timeRemaining !== 0 ? "Restart" : "Start"}
    </button>
  </main>

  <footer className="mt-24 py-12 border-t border-gray-800">
    <div className="container text-center text-sm text-gray-600">
      <p>© {new Date().getFullYear()} Pomodoro Timer. Focus on one thing at a time.</p>
    </div>
  </footer>
</div>
)

export default PomodoroTimerApp
